      className={`${baseClasses} ${sizeClasses[size]} ${variantClasses[variant]} ${className}`}
      data-testid="badge-premium"
    >
      <Crown className={iconSizes[size]} />
      {showText && <span>Premium</span>}
    </span>
  );
}

export function UnlimitedBadge({ className = '' }: { className?: string }) {
  const { t } = useLanguage();

  return (
    <span 
      className={`inline-flex items-center gap-1.5 text-xs font-medium px-2 py-0.5 rounded-full bg-gradient-to-r from-emerald-500/10 to-teal-500/10 text-emerald-600 dark:text-emerald-400 border border-emerald-200 dark:border-emerald-800 ${className}`}
      data-testid="badge-unlimited"
    >
      <Infinity className="w-3 h-3" />
      <span className="hidden sm:inline">{t.subscriptionPage.unlimited}</span>
    </span>
  );
}

export function PremiumFeatureIndicator({ 
  children, 
  label 
}: { 
  children: React.ReactNode;
  label?: string;
}) {
  const { t } = useLanguage();

  return (
    <div className="relative group">
      {children}
      <div className="absolute -top-1 -right-1 opacity-0 group-hover:opacity-100 transition-opacity">
        <span className="inline-flex items-center gap-0.5 text-[10px] font-medium px-1.5 py-0.5 rounded-full bg-amber-500 text-white shadow-sm">
          <Sparkles className="w-2.5 h-2.5" />
          {label || 'Premium'}
        </span>
      </div>
    </div>
  );
}

export function PremiumCard({ 
  children, 
  className = '' 
}: { 
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <div className={`relative overflow-hidden rounded-lg border-2 border-amber-200 dark:border-amber-800 bg-gradient-to-br from-amber-50/50 to-orange-50/30 dark:from-amber-900/10 dark:to-orange-900/5 ${className}`}>
      <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-bl from-amber-400/20 to-transparent rounded-full -translate-y-1/2 translate-x-1/2" />
      <div className="relative z-10">
        {children}
      </div>
    </div>
  );
}

export function UpgradeCTA({ compact = false }: { compact?: boolean }) {
  const { t } = useLanguage();

  if (compact) {
    return (
      <a 
        href="/dashboard/subscription"
        className="inline-flex items-center gap-1.5 text-xs font-medium px-3 py-1.5 rounded-full bg-gradient-to-r from-amber-500 to-orange-500 text-white shadow-md hover:shadow-lg hover:from-amber-400 hover:to-orange-400 transition-all"
        data-testid="link-upgrade-cta"
      >
        <Zap className="w-3 h-3" />
        {t.subscriptionPage.upgradeToPremium}
      </a>
    );
  }

  return (
    <div className="p-4 rounded-lg bg-gradient-to-r from-amber-500/10 to-orange-500/10 border border-amber-200 dark:border-amber-800">
      <div className="flex items-center gap-3">
        <div className="p-2 rounded-full bg-gradient-to-r from-amber-500 to-orange-500 text-white">
          <Crown className="w-5 h-5" />
        </div>
        <div className="flex-1">
          <p className="font-semibold text-foreground">{t.subscriptionPage.upgradeToPremium}</p>
          <p className="text-sm text-muted-foreground">{t.subscriptionPage.unlockAllFeatures}</p>
        </div>
        <a 
          href="/dashboard/subscription"
          className="inline-flex items-center gap-1.5 text-sm font-medium px-4 py-2 rounded-full bg-gradient-to-r from-amber-500 to-orange-500 text-white shadow-md hover:shadow-lg hover:from-amber-400 hover:to-orange-400 transition-all"
          data-testid="link-upgrade-cta"
        >
          <Zap className="w-4 h-4" />
          {t.subscriptionPage.subscribe}
        </a>
      </div>
    </div>
  );
}

client/src/pages/SharedStats.tsx.content:
import { useQuery } from '@tanstack/react-query';
import { useRoute, useLocation } from 'wouter';
import { ShareableStatsCard } from '@/components/ShareableStatsCard';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { GraduationCap, ArrowRight, Loader2 } from 'lucide-react';
import { useLanguage } from '@/lib/i18n/LanguageContext';
import type { SharedStats } from '@shared/schema';
import { Helmet } from 'react-helmet-async';

export default function SharedStatsPage() {
  const { language } = useLanguage();
  const [, params] = useRoute('/share/:token');
  const [, setLocation] = useLocation();
  const token = params?.token;

  const { data: stats, isLoading, error } = useQuery<SharedStats>({
    queryKey: ['/api/shared', token],
    queryFn: async () => {
      const response = await fetch(`/api/shared/${token}`);
      if (!response.ok) {
        throw new Error('Stats not found');
      }
      return response.json();
    },
    enabled: !!token,
  });

  if (isLoading) {
    return (
      <div className="min-h-screen bg-gradient-to-b from-background to-muted/30 flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  if (error || !stats) {
    return (
      <div className="min-h-screen bg-gradient-to-b from-background to-muted/30 flex items-center justify-center p-4">
        <Card className="max-w-md w-full">
          <CardContent className="pt-6 text-center">
            <GraduationCap className="w-12 h-12 mx-auto mb-4 text-muted-foreground" />
            <h1 className="text-xl font-bold mb-2" data-testid="text-stats-not-found">
              {language === 'fr' ? 'Stats non trouvées' : 'Stats not found'}
            </h1>
            <p className="text-muted-foreground mb-4">
              {language === 'fr' 
                ? 'Ce lien de partage n\'existe plus ou a expiré.'
                : 'This share link no longer exists or has expired.'}
            </p>
            <Button onClick={() => setLocation('/')} data-testid="button-go-home">
              {language === 'fr' ? 'Découvrir Corrige Tes Cours' : 'Discover Corrige Tes Cours'}
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  const pageTitle = stats.userName 
    ? `${stats.userName} - Performances | Corrige Tes Cours`
    : 'Performances | Corrige Tes Cours';

  const pageDescription = language === 'fr'
    ? `${stats.userName || 'Un étudiant'} a passé ${stats.totalQuizzes} quiz avec une moyenne de ${stats.averageScore}%. Découvre Corrige Tes Cours !`
    : `${stats.userName || 'A student'} took ${stats.totalQuizzes} quizzes with an average of ${stats.averageScore}%. Discover Corrige Tes Cours!`;

  return (
    <>
      <Helmet>
        <title>{pageTitle}</title>
        <meta name="description" content={pageDescription} />
        <meta property="og:title" content={pageTitle} />
        <meta property="og:description" content={pageDescription} />
        <meta property="og:type" content="website" />
        <meta property="og:url" content={`https://corrigetescours.com/share/${token}`} />
        <meta property="og:image" content="https://corrigetescours.com/og-image.png" />
        <meta property="og:image:width" content="1200" />
        <meta property="og:image:height" content="630" />
        <meta property="og:site_name" content="Corrige Tes Cours" />
        <meta name="twitter:card" content="summary_large_image" />
        <meta name="twitter:title" content={pageTitle} />
        <meta name="twitter:description" content={pageDescription} />
        <meta name="twitter:image" content="https://corrigetescours.com/og-image.png" />
      </Helmet>

      <div className="min-h-screen bg-gradient-to-b from-background to-muted/30 flex flex-col items-center justify-center p-4">
        <div className="mb-6 text-center">
          <div className="flex items-center justify-center gap-2 mb-2">
            <GraduationCap className="w-8 h-8 text-primary" />
            <span className="text-xl font-bold">Corrige Tes Cours</span>
          </div>
          <p className="text-muted-foreground text-sm">
            {language === 'fr' 
              ? 'L\'IA qui booste tes révisions'
              : 'AI that boosts your studies'}
          </p>
        </div>

        <div className="transform scale-[0.85] sm:scale-100 origin-center">
          <ShareableStatsCard
            totalQuizzes={stats.totalQuizzes}
            totalCourses={stats.totalCourses}
            averageScore={stats.averageScore}
            bestScore={stats.bestScore}
            userName={stats.userName || undefined}
          />
        </div>

        <div className="mt-8 text-center max-w-md">
          <h2 className="text-lg font-semibold mb-2" data-testid="text-cta-title">
            {language === 'fr' 
              ? 'Envie de suivre tes progrès aussi ?'
              : 'Want to track your progress too?'}
          </h2>
          <p className="text-muted-foreground text-sm mb-4">
            {language === 'fr' 
              ? 'Rejoins des milliers d\'étudiants qui révisent plus intelligemment avec Corrige Tes Cours'
              : 'Join thousands of students who study smarter with Corrige Tes Cours'}
          </p>
          <Button 
            size="lg" 
            onClick={() => setLocation('/auth')}
            className="gap-2"
            data-testid="button-join-now"
          >
            {language === 'fr' ? 'Commencer gratuitement' : 'Start for free'}
            <ArrowRight className="w-4 h-4" />
          </Button>
        </div>

        <p className="mt-8 text-xs text-muted-foreground">
          {language === 'fr' 
            ? 'Résumés IA • Quiz personnalisés • Chatbot 24/7'
            : 'AI Summaries • Personalized Quizzes • 24/7 Chatbot'}
        </p>
      </div>
    </>
  );
}

client/src/components/ShareStatsDialog.t.content:
import { useState, useRef, useCallback } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { useToast } from '@/hooks/use-toast';
import { useMutation, useQuery } from '@tanstack/react-query';
import { apiRequest, queryClient } from '@/lib/queryClient';
import { ShareableStatsCard } from './ShareableStatsCard';
import { ShareableStatsCardExport } from './ShareableStatsCardExport';
import { Share2, Download, Copy, Check, Crown, Link2 } from 'lucide-react';
import { useLanguage } from '@/lib/i18n/LanguageContext';
import { toPng } from 'html-to-image';
import type { Subscription, SharedStats } from '@shared/schema';

interface ShareStatsDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  stats: {
    totalQuizzes: number;
    totalCourses: number;
    averageScore: number;
    bestScore: number;
  };
  userName?: string;
}

export function ShareStatsDialog({ open, onOpenChange, stats, userName }: ShareStatsDialogProps) {
  const { t, language } = useLanguage();
  const { toast } = useToast();
  const cardRef = useRef<HTMLDivElement>(null);
  const exportCardRef = useRef<HTMLDivElement>(null);
  const [copied, setCopied] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);

  const { data: subscription } = useQuery<Subscription>({
    queryKey: ['/api/subscription'],
  });

  const isPremium = subscription?.status === 'premium';

  const generateShareMutation = useMutation({
    mutationFn: async () => {
      const response = await apiRequest('POST', '/api/share-stats');
      return response.json() as Promise<SharedStats>;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/share-stats'] });
    },
  });

  const { data: existingShareStats } = useQuery<SharedStats | null>({
    queryKey: ['/api/share-stats'],
  });

  const shareUrl = existingShareStats?.shareToken 
    ? `${window.location.origin}/share/${existingShareStats.shareToken}`
    : null;

  const handleGenerateLink = async () => {
    try {
      await generateShareMutation.mutateAsync();
      toast({
        title: language === 'fr' ? 'Lien créé !' : 'Link created!',
        description: language === 'fr' 
          ? 'Ton lien de partage est prêt'
          : 'Your share link is ready',
      });
    } catch (error) {
      toast({
        title: language === 'fr' ? 'Erreur' : 'Error',
        description: language === 'fr' 
          ? 'Impossible de créer le lien'
          : 'Failed to create link',
        variant: 'destructive',
      });
    }
  };

  const handleCopyLink = useCallback(() => {
    if (shareUrl) {
      navigator.clipboard.writeText(shareUrl);
      setCopied(true);
      toast({
        title: language === 'fr' ? 'Lien copié !' : 'Link copied!',
        description: language === 'fr' 
          ? 'Partage ce lien avec tes amis'
          : 'Share this link with your friends',
      });
      setTimeout(() => setCopied(false), 2000);
    }
  }, [shareUrl, toast, language]);

  const handleDownloadImage = async () => {
    if (!exportCardRef.current) return;

    setIsGenerating(true);
    try {
      const dataUrl = await toPng(exportCardRef.current, {
        cacheBust: true,
        pixelRatio: 2,
        quality: 1,
      });

      const link = document.createElement('a');
      link.download = `corrigetescours-stats-${Date.now()}.png`;
      link.href = dataUrl;
      link.click();

      toast({
        title: language === 'fr' ? 'Image téléchargée !' : 'Image downloaded!',
        description: language === 'fr' 
          ? 'Partage-la sur tes réseaux sociaux'
          : 'Share it on your social media',
      });
    } catch (error) {
      console.error('Image generation error:', error);
      toast({
        title: language === 'fr' ? 'Erreur' : 'Error',
        description: language === 'fr' 
          ? 'Impossible de générer l\'image'
          : 'Failed to generate image',
        variant: 'destructive',
      });
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-[95vw] sm:max-w-xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2" data-testid="share-dialog-title">
            <Share2 className="w-5 h-5" />
            {language === 'fr' ? 'Partager mes performances' : 'Share my performance'}
          </DialogTitle>
          <DialogDescription data-testid="share-dialog-description">
            {language === 'fr' 
              ? 'Montre tes progrès à tes amis et inspire-les !'
              : 'Show your progress to friends and inspire them!'}
          </DialogDescription>
        </DialogHeader>

        <div className="flex flex-col items-center gap-4 py-4">
          <div className="transform scale-[0.65] sm:scale-75 origin-center -my-16 sm:-my-12">
            <ShareableStatsCard
              ref={cardRef}
              totalQuizzes={stats.totalQuizzes}
              totalCourses={stats.totalCourses}
              averageScore={stats.averageScore}
              bestScore={stats.bestScore}
              userName={userName}
            />
          </div>

          <div style={{ position: 'absolute', left: '-9999px', top: '-9999px' }}>
            <ShareableStatsCardExport
              ref={exportCardRef}
              totalQuizzes={stats.totalQuizzes}
              totalCourses={stats.totalCourses}
              averageScore={stats.averageScore}
              bestScore={stats.bestScore}
              userName={userName}
              language={language as 'fr' | 'en'}
            />
          </div>

          <div className="w-full space-y-3">
            {isPremium ? (
              <>
                <Button
                  onClick={handleDownloadImage}
                  disabled={isGenerating}
                  className="w-full gap-2"
                  size="lg"
                  data-testid="button-download-image"
                >
                  <Download className="w-4 h-4" />
                  {isGenerating 
                    ? (language === 'fr' ? 'Génération...' : 'Generating...')
                    : (language === 'fr' ? 'Télécharger l\'image' : 'Download image')}
                </Button>

                <div className="flex gap-2">
                  {!shareUrl ? (
                    <Button
                      onClick={handleGenerateLink}
                      disabled={generateShareMutation.isPending}
                      variant="outline"
                      className="flex-1 gap-2"
                      data-testid="button-generate-link"
                    >
                      <Link2 className="w-4 h-4" />
                      {generateShareMutation.isPending
                        ? (language === 'fr' ? 'Création...' : 'Creating...')
                        : (language === 'fr' ? 'Créer un lien' : 'Create link')}
                    </Button>
                  ) : (
                    <Button
                      onClick={handleCopyLink}
                      variant="outline"
                      className="flex-1 gap-2"
                      data-testid="button-copy-link"
                    >
                      {copied ? (
                        <>
                          <Check className="w-4 h-4 text-green-500" />
                          {language === 'fr' ? 'Copié !' : 'Copied!'}
                        </>
                      ) : (
                        <>
                          <Copy className="w-4 h-4" />
                          {language === 'fr' ? 'Copier le lien' : 'Copy link'}
                        </>
                      )}
                    </Button>
                  )}
                </div>
              </>
            ) : (
              <>
                <div className="bg-gradient-to-r from-amber-500/10 to-orange-500/10 border border-amber-500/20 rounded-xl p-4 text-center">
                  <div className="flex items-center justify-center gap-2 mb-2">
                    <Crown className="w-5 h-5 text-amber-500" />
                    <span className="font-semibold text-amber-600 dark:text-amber-400">
                      {language === 'fr' ? 'Fonctionnalité Premium' : 'Premium Feature'}
                    </span>
                  </div>
                  <p className="text-sm text-muted-foreground mb-3">
                    {language === 'fr' 
                      ? 'Passe au Premium pour télécharger l\'image directement'
                      : 'Upgrade to Premium to download the image directly'}
                  </p>
                </div>

                {!shareUrl ? (
                  <Button
                    onClick={handleGenerateLink}
                    disabled={generateShareMutation.isPending}
                    className="w-full gap-2"
                    size="lg"
                    data-testid="button-generate-link-free"
                  >
                    <Link2 className="w-4 h-4" />
                    {generateShareMutation.isPending
                      ? (language === 'fr' ? 'Création...' : 'Creating...')
                      : (language === 'fr' ? 'Créer un lien de partage' : 'Create share link')}
                  </Button>
                ) : (
                  <Button
                    onClick={handleCopyLink}
                    className="w-full gap-2"
                    size="lg"
                    data-testid="button-copy-link-free"
                  >
                    {copied ? (
                      <>
                        <Check className="w-4 h-4" />
                        {language === 'fr' ? 'Lien copié !' : 'Link copied!'}
                      </>
                    ) : (
                      <>
                        <Copy className="w-4 h-4" />
                        {language === 'fr' ? 'Copier le lien' : 'Copy link'}
                      </>
                    )}
                  </Button>
                )}

                {shareUrl && (
                  <p className="text-xs text-center text-muted-foreground">
                    {language === 'fr' 
                      ? 'Les visiteurs verront un aperçu de tes stats et seront redirigés vers l\'app'
                      : 'Visitors will see a preview of your stats and be redirected to the app'}
                  </p>
                )}
              </>
            )}
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/ShareableStatsCard.content:
import { forwardRef } from 'react';
import { Target, TrendingUp, Award, BookOpen, GraduationCap } from 'lucide-react';
import { useLanguage } from '@/lib/i18n/LanguageContext';

interface ShareableStatsCardProps {
  totalQuizzes: number;
  totalCourses: number;
  averageScore: number;
  bestScore: number;
  userName?: string;
}

export const ShareableStatsCard = forwardRef<HTMLDivElement, ShareableStatsCardProps>(
  ({ totalQuizzes, totalCourses, averageScore, bestScore, userName }, ref) => {
    const { t, language } = useLanguage();

    const getScoreGradient = (score: number) => {
      if (score >= 80) return 'from-emerald-500 to-green-600';
      if (score >= 60) return 'from-amber-500 to-orange-600';
      return 'from-red-500 to-rose-600';
    };

    const getScoreIcon = (score: number) => {
      if (score >= 80) return 'excellent';
      if (score >= 60) return 'good';
      return 'learning';
    };

    return (
      <div
        ref={ref}
        className="w-[400px] h-[500px] relative overflow-hidden rounded-3xl"
        style={{
          background: 'linear-gradient(135deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%)',
        }}
      >
        <div className="absolute inset-0 opacity-30">
          <div className="absolute top-10 left-10 w-32 h-32 rounded-full bg-purple-500/20 blur-3xl" />
          <div className="absolute bottom-20 right-10 w-40 h-40 rounded-full bg-blue-500/20 blur-3xl" />
          <div className="absolute top-1/2 left-1/2 w-24 h-24 rounded-full bg-emerald-500/20 blur-3xl" />
        </div>

        <div className="relative z-10 flex flex-col h-full p-6">
          <div className="flex items-center gap-2 mb-4">
            <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-primary to-primary/60 flex items-center justify-center">
              <GraduationCap className="w-6 h-6 text-white" />
            </div>
            <div>
              <p className="text-white/60 text-xs font-medium tracking-wide uppercase">
                {language === 'fr' ? 'Mes statistiques' : 'My Statistics'}
              </p>
              {userName && (
                <p className="text-white font-semibold text-sm">{userName}</p>
              )}
            </div>
          </div>

          <div className="flex-1 flex flex-col justify-center gap-4">
            <div className="grid grid-cols-2 gap-3">
              <div className="bg-white/10 backdrop-blur-sm rounded-2xl p-4 border border-white/10">
                <div className="flex items-center gap-2 mb-2">
                  <div className="w-8 h-8 rounded-lg bg-blue-500/20 flex items-center justify-center">
                    <Target className="w-4 h-4 text-blue-400" />
                  </div>
                </div>
                <p className="text-3xl font-bold text-white">{totalQuizzes}</p>
                <p className="text-white/60 text-xs mt-1">
                  {language === 'fr' ? 'Quiz passés' : 'Quizzes taken'}
                </p>
              </div>

              <div className="bg-white/10 backdrop-blur-sm rounded-2xl p-4 border border-white/10">
                <div className="flex items-center gap-2 mb-2">
                  <div className="w-8 h-8 rounded-lg bg-purple-500/20 flex items-center justify-center">
                    <BookOpen className="w-4 h-4 text-purple-400" />
                  </div>
                </div>
                <p className="text-3xl font-bold text-white">{totalCourses}</p>
                <p className="text-white/60 text-xs mt-1">
                  {language === 'fr' ? 'Cours actifs' : 'Active courses'}
                </p>
              </div>
            </div>

            <div className={`bg-gradient-to-r ${getScoreGradient(averageScore)} rounded-2xl p-5 relative overflow-hidden`}>
              <div className="absolute top-0 right-0 opacity-10 transform translate-x-4 -translate-y-2">
                <Award className="w-24 h-24 text-white" />
              </div>
              <div className="flex items-center gap-2 mb-2">
                <TrendingUp className="w-5 h-5 text-white/80" />
                <p className="text-white/80 text-sm font-medium">
                  {language === 'fr' ? 'Score moyen' : 'Average score'}
                </p>
              </div>
              <p className="text-5xl font-bold text-white">{averageScore}%</p>
            </div>

            <div className="bg-white/10 backdrop-blur-sm rounded-2xl p-4 border border-white/10 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-amber-500/20 flex items-center justify-center">
                  <Award className="w-5 h-5 text-amber-400" />
                </div>
                <div>
                  <p className="text-white/60 text-xs">
                    {language === 'fr' ? 'Meilleur score' : 'Best score'}
                  </p>
                  <p className="text-white font-semibold">
                    {language === 'fr' ? 'Record personnel' : 'Personal record'}
                  </p>
                </div>
              </div>
              <p className="text-3xl font-bold text-amber-400">{bestScore}%</p>
            </div>
          </div>

          <div className="flex items-center justify-center gap-2 pt-4 border-t border-white/10">
            <div className="w-6 h-6 rounded-lg bg-gradient-to-br from-primary to-primary/60 flex items-center justify-center">
              <GraduationCap className="w-4 h-4 text-white" />
            </div>
            <span className="text-white/40 text-sm font-medium">corrigetescours.com</span>
          </div>
        </div>
      </div>
    );
  }
);

ShareableStatsCard.displayName = 'ShareableStatsCard';
